window.QSAFE_PROJECTS = {"index": [{"id": "starknet", "name": "Starknet", "type": "Validity rollup (L2)", "status": "assessed", "reviewed": "2026-06-24"}, {"id": "ethereum", "name": "Ethereum", "type": "L1 + rollup settlement layer", "status": "queued"}, {"id": "solana", "name": "Solana", "type": "Monolithic L1", "status": "queued"}, {"id": "bitcoin", "name": "Bitcoin", "type": "Monolithic UTXO L1", "status": "queued"}], "assessments": {"starknet": {"id": "starknet", "name": "Starknet", "type": "Validity rollup (L2)", "reviewed": "2026-06-24", "summary": "Starknet's proving is post-quantum secure — STARKs are hash-based — but its accounts, settlement, oracles and networking still rely on breakable elliptic-curve crypto. A textbook case of the project's core message: a quantum-safe proof system does not by itself make a chain quantum-safe.", "links": {"Website": "https://www.starknet.io", "Docs": "https://docs.starknet.io", "GitHub": "https://github.com/starkware-libs"}, "assessment": {"1.1": {"verdict": "fail", "scheme": "Stark-curve ECDSA (Falcon via AA, opt-in)", "why": "Default accounts sign with Stark-curve ECDSA, which Shor breaks. Native account abstraction lets users opt into Falcon-512 (demonstrated by s2morrow), but it is not the default."}, "1.2": {"verdict": "fail", "scheme": "Stark-curve / secp256 keys", "why": "Stored keys are the same breakable curve keys; PQ custody only follows once the account itself adopts a PQ scheme."}, "1.3": {"verdict": "fail", "scheme": "Classical threshold", "why": "Multi-party signing still splits classical keys; PQ threshold signing is research-stage."}, "1.4": {"verdict": "pass", "scheme": "Native account abstraction", "why": "Native AA is live and can verify PQ signatures inside the account — the migration vehicle exists with no hard fork required. This is Starknet's structural advantage for going quantum-safe."}, "1.5": {"verdict": "fail", "scheme": "Session keys, P-256 passkeys", "why": "Session keys and passkeys rely on breakable curves (Stark-curve, secp256r1)."}, "1.6": {"verdict": "fail", "scheme": "Starknet.id", "why": "Naming/identity inherits the controlling account's signature, which is breakable until accounts move to PQ."}, "1.7": {"verdict": "fail", "scheme": "Account-signed votes", "why": "Governance is authorized by account signatures, which are breakable today."}, "2.1": {"verdict": "fail", "scheme": "ECDSA checks in Cairo", "why": "Contracts that verify signatures use breakable ECDSA checks; there is no PQ-signature precompile yet."}, "2.2": {"verdict": "na", "scheme": "", "why": "Starknet's own validity proving is STARK-based; pairing-based on-chain verifier contracts are not core to the protocol."}, "2.3": {"verdict": "fail", "scheme": "Pragma / oracle signatures", "why": "On-chain oracle feeds authenticate data with classical signatures."}, "2.4": {"verdict": "fail", "scheme": "EC-based VRF", "why": "On-chain verifiable randomness is elliptic-curve based; PQ VRFs are research-stage."}, "2.5": {"verdict": "na", "scheme": "", "why": "Starknet does not rely on a verifiable delay function."}, "3.1": {"verdict": "fail", "scheme": "Sequencer signing key", "why": "The sequencer authorizes batches with a classical signing key."}, "3.2": {"verdict": "pass", "scheme": "STARK / FRI", "why": "Proving uses STARKs (hash-based, FRI), which are post-quantum secure. This is Starknet's central quantum strength."}, "3.3": {"verdict": "pass", "scheme": "Transparent (FRI)", "why": "STARKs use a transparent setup — there is no trusted-setup secret for a quantum computer to recover."}, "3.4": {"verdict": "fail", "scheme": "Ethereum KZG blobs", "why": "Data availability is posted to Ethereum via KZG blobs, which are pairing-based and breakable."}, "3.5": {"verdict": "fail", "scheme": "Pedersen → Poseidon", "why": "The state tree still uses EC-based Pedersen hashing; migration to hash-based Poseidon (the PQ target) is underway but not complete."}, "3.6": {"verdict": "pass", "scheme": "Cairo VM", "why": "The VM carries no cryptography of its own; signature and proof checks live in other components."}, "4.1": {"verdict": "na", "scheme": "", "why": "Finality derives from Ethereum verifying the STARK proof; Starknet has no independent validator-signature consensus set yet (decentralized consensus is upcoming)."}, "4.2": {"verdict": "pass", "scheme": "STARK verification", "why": "External verification is via STARK proofs (hash-based), not a BLS signing committee."}, "4.3": {"verdict": "fail", "scheme": "L1 verifier + operator keys", "why": "Settlement to Ethereum uses an L1 verifier contract and operator keys that rely on Ethereum's breakable ECDSA."}, "4.4": {"verdict": "fail", "scheme": "StarkGate / external bridges", "why": "The canonical bridge inherits settlement's breakable crypto; third-party bridges use classical committee signatures."}, "4.5": {"verdict": "na", "scheme": "", "why": "Starknet does not use restaking / AVS attestations in its core protocol."}, "4.6": {"verdict": "na", "scheme": "", "why": "Payment channels / HTLCs are not part of the core protocol."}, "4.7": {"verdict": "na", "scheme": "", "why": "Block building uses a single sequencer; there is no MEV-Boost / PBS relay market."}, "5.1": {"verdict": "fail", "scheme": "Classical TLS / QUIC", "why": "Node-to-node transport uses classical key exchange; PQ/hybrid is not yet deployed."}, "5.2": {"verdict": "fail", "scheme": "Classical node keys", "why": "Node identity keys use breakable classical signatures."}, "5.3": {"verdict": "fail", "scheme": "Classical TLS", "why": "RPC / API connections use classical TLS."}, "5.4": {"verdict": "na", "scheme": "", "why": "No protocol-level stealth-address / on-chain key-agreement standard is deployed (privacy features are emerging)."}, "5.5": {"verdict": "na", "scheme": "", "why": "Application-layer encryption / privacy is emerging, not a core deployed feature."}}}}};
